/* ═══════════════════════════════════════════════════════════════
   HUBORA — Shared UI Components
   components/ui/hubora-ui.tsx
   ═══════════════════════════════════════════════════════════════ */

   import * as React from "react"
   import { cn } from "@/lib/utils"
   
   /* ─────────────────────────────────────────
      CARD
      ───────────────────────────────────────── */
   interface CardProps extends React.HTMLAttributes<HTMLDivElement> {
     hover?: boolean
     /** Tilts the card 1–2deg for sticker feel */
     tilt?: boolean
     padding?: "sm" | "md" | "lg" | "none"
   }
   
   export function Card({
     className,
     hover = false,
     tilt = false,
     padding = "md",
     children,
     ...props
   }: CardProps) {
     const padMap = { none: "", sm: "p-4", md: "p-5", lg: "p-7" }
     return (
       <div
         className={cn(
           "bg-white border-2 border-[#0D0D0D] rounded-xl",
           "shadow-[4px_4px_0px_0px_#0D0D0D]",
           hover && "transition-all duration-150 hover:-translate-x-[1px] hover:-translate-y-[1px] hover:shadow-[5px_5px_0px_0px_#0D0D0D] cursor-pointer",
           tilt && "rotate-[1deg]",
           padMap[padding],
           className
         )}
         {...props}
       >
         {children}
       </div>
     )
   }
   
   /* ─────────────────────────────────────────
      TAG / CHIP
      ───────────────────────────────────────── */
   interface TagProps extends React.HTMLAttributes<HTMLSpanElement> {
     variant?: "default" | "violet" | "acid" | "success" | "error" | "ink"
     size?: "sm" | "md"
   }
   
   export function Tag({
     className,
     variant = "default",
     size = "sm",
     children,
     ...props
   }: TagProps) {
     const variantMap = {
       default: "bg-[#EDE8FF] text-[#4A4A6A] border-[#9B94B8]",
       violet:  "bg-[#7F00FF] text-white border-[#3B0080]",
       acid:    "bg-[#DFFF00] text-[#0D0D0D] border-[#AACC00]",
       success: "bg-[#DCFCE7] text-[#166534] border-[#166534]",
       error:   "bg-[#FEE2E2] text-[#991B1B] border-[#991B1B]",
       ink:     "bg-[#0D0D0D] text-white border-[#0D0D0D]",
     }
     const sizeMap = {
       sm: "text-[10px] px-2.5 py-0.5",
       md: "text-[12px] px-3 py-1",
     }
     return (
       <span
         className={cn(
           "inline-flex items-center gap-1 font-mono font-bold uppercase tracking-wider",
           "border rounded-full",
           variantMap[variant],
           sizeMap[size],
           className
         )}
         {...props}
       >
         {children}
       </span>
     )
   }
   
   /* ─────────────────────────────────────────
      AVATAR
      ───────────────────────────────────────── */
   interface AvatarProps {
     src?: string
     fallback: string
     size?: "xs" | "sm" | "md" | "lg" | "xl"
     className?: string
     /** Sticker style: white border + ink outline */
     sticker?: boolean
     gradient?: "violet" | "teal" | "amber" | "rose"
   }
   
   export function Avatar({
     src,
     fallback,
     size = "md",
     className,
     sticker = false,
     gradient = "violet",
   }: AvatarProps) {
     const sizeMap = {
       xs: "w-6 h-6 text-[10px] rounded-md",
       sm: "w-8 h-8 text-[12px] rounded-lg",
       md: "w-10 h-10 text-[14px] rounded-xl",
       lg: "w-14 h-14 text-[20px] rounded-2xl",
       xl: "w-20 h-20 text-[28px] rounded-2xl",
     }
     const gradMap = {
       violet: "from-[#3B0080] to-[#9B30FF]",
       teal:   "from-[#0D9488] to-[#0EA5E9]",
       amber:  "from-[#D97706] to-[#F59E0B]",
       rose:   "from-[#BE185D] to-[#F43F5E]",
     }
     return (
       <div
         className={cn(
           "flex items-center justify-content-center shrink-0 overflow-hidden",
           "bg-gradient-to-br font-display text-white font-black",
           `bg-gradient-to-br ${gradMap[gradient]}`,
           sizeMap[size],
           sticker && "border-[3px] border-white outline-2 outline outline-[#0D0D0D]",
           className
         )}
       >
         {src ? (
           <img src={src} alt={fallback} className="w-full h-full object-cover" />
         ) : (
           <span className="flex items-center justify-center w-full h-full">{fallback[0].toUpperCase()}</span>
         )}
       </div>
     )
   }
   
   /* ─────────────────────────────────────────
      BADGE (notification dot / counter)
      ───────────────────────────────────────── */
   interface BadgeProps {
     count?: number
     variant?: "violet" | "acid" | "error"
     className?: string
   }
   
   export function Badge({ count, variant = "violet", className }: BadgeProps) {
     if (!count) return null
     const varMap = {
       violet: "bg-[#7F00FF] text-white",
       acid:   "bg-[#DFFF00] text-[#0D0D0D]",
       error:  "bg-[#FF3B3B] text-white",
     }
     return (
       <span
         className={cn(
           "inline-flex items-center justify-center",
           "min-w-[18px] h-[18px] px-1",
           "text-[10px] font-mono font-bold",
           "rounded-full border border-[#0D0D0D]",
           varMap[variant],
           className
         )}
       >
         {count > 99 ? "99+" : count}
       </span>
     )
   }
   
   /* ─────────────────────────────────────────
      INPUT
      ───────────────────────────────────────── */
   interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
     label?: string
     error?: string
     leftSlot?: React.ReactNode
   }
   
   export function Input({ label, error, leftSlot, className, ...props }: InputProps) {
     return (
       <div className="flex flex-col gap-1.5">
         {label && (
           <label className="text-[12px] font-mono font-bold uppercase tracking-wider text-[#4A4A6A]">
             {label}
           </label>
         )}
         <div className="relative">
           {leftSlot && (
             <div className="absolute left-3 top-1/2 -translate-y-1/2 text-[#9B94B8]">
               {leftSlot}
             </div>
           )}
           <input
             className={cn(
               "w-full bg-white text-[#0D0D0D]",
               "border-2 border-[#0D0D0D] rounded-[10px]",
               "px-4 py-2.5 text-[14px] font-body",
               "placeholder:text-[#9B94B8]",
               "shadow-[3px_3px_0px_0px_#0D0D0D]",
               "focus:outline-none focus:border-[#7F00FF] focus:shadow-[3px_3px_0px_0px_#3B0080]",
               "transition-all duration-150",
               leftSlot && "pl-9",
               error && "border-[#FF3B3B] shadow-[3px_3px_0px_0px_#FF3B3B]",
               className
             )}
             {...props}
           />
         </div>
         {error && (
           <p className="text-[11px] font-mono text-[#FF3B3B]">{error}</p>
         )}
       </div>
     )
   }
   
   /* ─────────────────────────────────────────
      TEXTAREA
      ───────────────────────────────────────── */
   interface TextareaProps extends React.TextareaHTMLAttributes<HTMLTextAreaElement> {
     label?: string
   }
   
   export function Textarea({ label, className, ...props }: TextareaProps) {
     return (
       <div className="flex flex-col gap-1.5">
         {label && (
           <label className="text-[12px] font-mono font-bold uppercase tracking-wider text-[#4A4A6A]">
             {label}
           </label>
         )}
         <textarea
           className={cn(
             "w-full bg-white text-[#0D0D0D] resize-none",
             "border-2 border-[#0D0D0D] rounded-[10px]",
             "px-4 py-2.5 text-[14px] font-body",
             "placeholder:text-[#9B94B8]",
             "shadow-[3px_3px_0px_0px_#0D0D0D]",
             "focus:outline-none focus:border-[#7F00FF] focus:shadow-[3px_3px_0px_0px_#3B0080]",
             "transition-all duration-150",
             className
           )}
           {...props}
         />
       </div>
     )
   }
   
   /* ─────────────────────────────────────────
      SIDEBAR ITEM
      ───────────────────────────────────────── */
   interface SidebarItemProps {
     icon: React.ReactNode
     label: string
     active?: boolean
     badge?: number
     onClick?: () => void
     href?: string
   }
   
   export function SidebarItem({ icon, label, active, badge, onClick }: SidebarItemProps) {
     return (
       <button
         onClick={onClick}
         className={cn(
           "w-full flex items-center gap-3 px-3 py-2.5 rounded-[10px]",
           "text-[13px] font-body font-medium",
           "transition-all duration-150 text-left",
           active
             ? "bg-[#EDE8FF] text-[#7F00FF] border-l-4 border-[#7F00FF] font-semibold"
             : "text-[#4A4A6A] hover:bg-[#F4F0FF] hover:text-[#0D0D0D]"
         )}
       >
         <span className="text-[18px] w-6 flex items-center justify-center shrink-0">{icon}</span>
         <span className="flex-1">{label}</span>
         {badge !== undefined && badge > 0 && <Badge count={badge} />}
       </button>
     )
   }
   
   /* ─────────────────────────────────────────
      SECTION LABEL (eyebrow text)
      ───────────────────────────────────────── */
   export function SectionLabel({ children, className }: { children: React.ReactNode; className?: string }) {
     return (
       <p className={cn(
         "font-mono text-[10px] font-bold uppercase tracking-[0.18em] text-[#7F00FF]",
         className
       )}>
         {children}
       </p>
     )
   }
   
   /* ─────────────────────────────────────────
      STAT CARD
      ───────────────────────────────────────── */
   interface StatCardProps {
     label: string
     value: string
     change?: string
     changeType?: "up" | "down" | "neutral"
     icon?: string
   }
   
   export function StatCard({ label, value, change, changeType = "neutral", icon }: StatCardProps) {
     const changeColor = {
       up:      "text-[#00C48C]",
       down:    "text-[#FF3B3B]",
       neutral: "text-[#9B94B8]",
     }
     return (
       <Card padding="md" className="flex flex-col gap-2">
         <div className="flex items-center justify-between">
           <p className="font-mono text-[10px] font-bold uppercase tracking-wider text-[#9B94B8]">{label}</p>
           {icon && <span className="text-lg">{icon}</span>}
         </div>
         <p className="font-display text-[28px] leading-none text-[#0D0D0D]">{value}</p>
         {change && (
           <p className={cn("font-mono text-[11px] font-bold", changeColor[changeType])}>
             {changeType === "up" ? "↑" : changeType === "down" ? "↓" : "→"} {change}
           </p>
         )}
       </Card>
     )
   }
   
   /* ─────────────────────────────────────────
      PLAN CARD
      ───────────────────────────────────────── */
   interface PlanCardProps {
     name: string
     price: string
     period?: string
     description: string
     features: string[]
     featured?: boolean
     featuredLabel?: string
     onSubscribe?: () => void
     subscribeLabel?: string
   }
   
   export function PlanCard({
     name,
     price,
     period = "/month",
     description,
     features,
     featured,
     featuredLabel = "Most Popular",
     onSubscribe,
     subscribeLabel = `Subscribe ${name}`,
   }: PlanCardProps) {
     return (
       <div className={cn(
         "relative bg-white border-2 rounded-xl p-7 flex flex-col gap-5",
         "transition-all duration-150",
         featured
           ? "border-[#7F00FF] shadow-[6px_6px_0px_0px_#3B0080] hover:-translate-x-[2px] hover:-translate-y-[2px] hover:shadow-[8px_8px_0px_0px_#3B0080]"
           : "border-[#0D0D0D] shadow-[4px_4px_0px_0px_#0D0D0D] hover:-translate-x-[1px] hover:-translate-y-[1px] hover:shadow-[5px_5px_0px_0px_#0D0D0D]"
       )}>
         {featured && (
           <div className="absolute -top-3.5 left-1/2 -translate-x-1/2">
             <span className="bg-[#DFFF00] text-[#0D0D0D] border-2 border-[#0D0D0D] text-[10px] font-mono font-black uppercase tracking-wider px-3 py-1 rounded-full shadow-[2px_2px_0px_0px_#0D0D0D]">
               ⭐ {featuredLabel}
             </span>
           </div>
         )}
         <div>
           <p className="font-mono text-[11px] font-bold uppercase tracking-widest text-[#9B94B8] mb-1">{name}</p>
           <div className="flex items-baseline gap-1">
             <span className="font-display text-[36px] leading-none text-[#0D0D0D]">{price}</span>
             <span className="font-body text-[13px] text-[#9B94B8]">{period}</span>
           </div>
           <p className="text-[13px] text-[#4A4A6A] mt-2 leading-relaxed">{description}</p>
         </div>
         <ul className="flex flex-col gap-2.5 flex-1">
           {features.map((f, i) => (
             <li key={i} className="flex items-start gap-2.5 text-[13px] text-[#0D0D0D]">
               <span className="mt-0.5 w-4 h-4 rounded-full bg-[#7F00FF] text-white text-[9px] font-black flex items-center justify-center shrink-0">✓</span>
               {f}
             </li>
           ))}
         </ul>
         <button
           onClick={onSubscribe}
           className={cn(
             "w-full py-2.5 rounded-[10px] font-body font-semibold text-[14px]",
             "border-2 border-[#0D0D0D]",
             "transition-all duration-150",
             "active:translate-x-[2px] active:translate-y-[2px] active:shadow-none",
             featured
               ? "bg-[#7F00FF] text-white shadow-[4px_4px_0px_0px_#0D0D0D] hover:bg-[#9B30FF] hover:-translate-x-[1px] hover:-translate-y-[1px] hover:shadow-[5px_5px_0px_0px_#0D0D0D]"
               : "bg-white text-[#0D0D0D] shadow-[4px_4px_0px_0px_#0D0D0D] hover:bg-[#EDE8FF] hover:-translate-x-[1px] hover:-translate-y-[1px] hover:shadow-[5px_5px_0px_0px_#0D0D0D]"
           )}
         >
           {subscribeLabel}
         </button>
       </div>
     )
   }
   
   /* ─────────────────────────────────────────
      CONTENT TYPE ICON
      ───────────────────────────────────────── */
   const contentTypeConfig = {
     video: { emoji: "🎬", bg: "bg-[#FEE2E2]", border: "border-[#FCA5A5]" },
     image: { emoji: "🖼️", bg: "bg-[#DCFCE7]", border: "border-[#86EFAC]" },
     pdf:   { emoji: "📄", bg: "bg-[#FEF9C3]", border: "border-[#FDE047]" },
     text:  { emoji: "📝", bg: "bg-[#EDE8FF]", border: "border-[#C084FC]" },
     audio: { emoji: "🎵", bg: "bg-[#FDE68A]", border: "border-[#F59E0B]" },
   }
   
   export function ContentTypeIcon({ type }: { type: keyof typeof contentTypeConfig }) {
     const cfg = contentTypeConfig[type]
     return (
       <div className={cn(
         "w-12 h-12 rounded-xl border-2 flex items-center justify-center text-[22px] shrink-0",
         cfg.bg, cfg.border
       )}>
         {cfg.emoji}
       </div>
     )
   }
   
   /* ─────────────────────────────────────────
      LOCKED CONTENT OVERLAY
      ───────────────────────────────────────── */
   export function LockedOverlay({ planName }: { planName: string }) {
     return (
       <div className="mt-3 flex items-center gap-2.5 px-4 py-3 rounded-[10px] bg-[#EDE8FF] border-2 border-dashed border-[#C084FC]">
         <span className="text-lg">🔒</span>
         <p className="text-[13px] font-body font-semibold text-[#7F00FF]">
           Upgrade to <span className="font-black">{planName}</span> to unlock this content
         </p>
       </div>
     )
   }
   
   /* ─────────────────────────────────────────
      HUB CARD (browse/feed)
      ───────────────────────────────────────── */
   interface HubCardProps {
     name: string
     handle: string
     subscriberCount: string
     tags: string[]
     plan?: string
     emoji: string
     gradient: string
     onClick?: () => void
   }
   
   export function HubCard({ name, handle, subscriberCount, tags, plan, emoji, gradient, onClick }: HubCardProps) {
     return (
       <Card hover className="overflow-hidden p-0" onClick={onClick}>
         <div className={cn("h-[90px] relative flex items-center justify-center", gradient)}>
           <div className="absolute bottom-[-18px] left-4 w-10 h-10 rounded-xl bg-white border-2 border-[#0D0D0D] flex items-center justify-center text-xl shadow-[2px_2px_0px_0px_#0D0D0D]">
             {emoji}
           </div>
         </div>
         <div className="p-4 pt-7">
           <h3 className="font-display text-[15px] mb-0.5">{name}</h3>
           <p className="font-mono text-[10px] text-[#9B94B8] mb-2">{handle} · {subscriberCount} subs</p>
           <div className="flex flex-wrap gap-1.5 mb-3">
             {tags.map(t => <Tag key={t}>{t}</Tag>)}
           </div>
           {plan && (
             <p className="font-mono text-[11px] font-bold text-[#7F00FF]">✓ {plan}</p>
           )}
         </div>
       </Card>
     )
   }